import { Connection } from '../connection';

interface Migration {
  version: string;
  sql: string;
}

export class MigrationRunner {
  private connection: Connection;
  private migrations: Migration[] = [];
  private applied: Set<string> = new Set();

  constructor(connection: Connection) {
    this.connection = connection;
  }

  add(version: string, sql: string): void {
    this.migrations.push({ version, sql });
  }

  async run(): Promise<void> {
    // Sort by version to ensure order
    const sorted = [...this.migrations].sort((a, b) =>
      a.version.localeCompare(b.version)
    );
    for (const migration of sorted) {
      if (!this.applied.has(migration.version)) {
        await this.connection.execute(migration.sql);
        this.applied.add(migration.version);
      }
    }
  }
}
